import theme from '../theme'

const Link = ({ link, title }) => {
    return (
        <>
            <style>{style}</style>
            <li>
                <a target="_blank" href={link}>{title}</a>
            </li>
        </>
    )
}

const style = `
   a {
    color:grey;
    text-decoration:none;
  }
  a:hover {
    color:white;
  }
`

export default Link
